    std::string DirectoryName2(const std::string& fullPath)
    {
        size_t slash = fullPath.find_last_of("\\/");
        return slash == std::string::npos ? std::string(".") : fullPath.substr(0, slash);
    }

    std::string CombinePath2(const std::string& left, const std::string& right)
    {
        if (left.empty())
        {
            return right;
        }

        char tail = left[left.size() - 1];
        return (tail == '\\' || tail == '/') ? left + right : left + "\\" + right;
    }

    bool FileExists2(const std::string& path)
    {
        DWORD attrs = GetFileAttributesA(path.c_str());
        return attrs != INVALID_FILE_ATTRIBUTES && (attrs & FILE_ATTRIBUTE_DIRECTORY) == 0;
    }

    std::string ModuleDirectory2()
    {
        HMODULE selfModule = NULL;
        if (GetModuleHandleExA(GET_MODULE_HANDLE_EX_FLAG_FROM_ADDRESS | GET_MODULE_HANDLE_EX_FLAG_UNCHANGED_REFCOUNT,
            reinterpret_cast<LPCSTR>(&ModuleDirectory2), &selfModule))
        {
            char path[MAX_PATH] = { 0 };
            DWORD length = GetModuleFileNameA(selfModule, path, MAX_PATH);
            if (length > 0 && length < MAX_PATH)
            {
                return DirectoryName2(path);
            }
        }

        return std::string(".");
    }

