    std::map<tag_t, NXOpen::Features::Feature*> BuildNeutralFactorFeatureByFace(NXOpen::Body* body)
    {
        std::map<tag_t, NXOpen::Features::Feature*> featureByFace;
        if (body == NULL)
        {
            return featureByFace;
        }

        try
        {
            std::vector<NXOpen::Features::Feature*> features = body->GetFeatures();
            for (size_t i = 0; i < features.size(); ++i)
            {
                NXOpen::Features::Feature* feature = features[i];
                if (!IsNeutralFactorFeature(feature))
                {
                    continue;
                }

                std::vector<NXOpen::Face*> faces = feature->GetFaces();
                for (size_t j = 0; j < faces.size(); ++j)
                {
                    if (faces[j] != NULL && IsAlive(faces[j]->Tag()))
                    {
                        featureByFace[faces[j]->Tag()] = feature;
                    }
                }
            }
        }
        catch (...)
        {
        }

        return featureByFace;
    }

    int CommitNeutralFactorFeature(
        NXOpen::Part* part,
        NXOpen::Features::Feature* existingFeature,
        const std::vector<NXOpen::Face*>& faces,
        double neutralFactor)
    {
        if (part == NULL || faces.empty())
        {
            return 0;
        }

        std::vector<NXOpen::Face*> validFaces;
        std::map<tag_t, bool> seen;
        for (size_t i = 0; i < faces.size(); ++i)
        {
            NXOpen::Face* face = faces[i];
            if (face == NULL || !IsAlive(face->Tag()) || seen[face->Tag()])
            {
                continue;
            }

            validFaces.push_back(face);
            seen[face->Tag()] = true;
        }

        if (validFaces.empty())
        {
            return 0;
        }

        NXOpen::Features::SheetMetal::ResizeNeutralFactorBuilder* resizeBuilder = NULL;
        try
        {
            resizeBuilder = part->Features()->SheetmetalManager()->CreateResizeNeutralFactorBuilder(existingFeature);
            resizeBuilder->SetUseGlobal(false);
            resizeBuilder->NeutralFactor()->SetFormula(FormatDouble(neutralFactor, 12));

            NXOpen::SelectionIntentRuleOptions* ruleOptions = part->ScRuleFactory()->CreateRuleOptions();
            ruleOptions->SetSelectedFromInactive(false);
            NXOpen::FaceDumbRule* faceRule = part->ScRuleFactory()->CreateRuleFaceDumb(validFaces, ruleOptions);
            delete ruleOptions;

            std::vector<NXOpen::SelectionIntentRule*> rules(1);
            rules[0] = faceRule;
            resizeBuilder->BendFaces()->ReplaceRules(rules, false);

            NXOpen::Features::Feature* feature = resizeBuilder->CommitFeature();
            resizeBuilder->Destroy();
            resizeBuilder = NULL;
            theSession->CleanUpFacetedFacesAndEdges();
            return feature == NULL ? 0 : static_cast<int>(validFaces.size());
        }
        catch (...)
        {
            if (resizeBuilder != NULL)
            {
                try
                {
                    resizeBuilder->Destroy();
                }
                catch (...)
                {
                }
            }

            return 0;
        }
    }

    int ApplyNeutralFactorByRules(
        NXOpen::Part* part,
        NXOpen::Features::SheetMetal::SheetmetalManager* manager,
        NXOpen::Body* body,
        const RuleConfig& ruleConfig)
    {
        if (part == NULL || manager == NULL || body == NULL)
        {
            return 0;
        }

        std::vector<NXOpen::Face*> innerBendFaces;
        std::vector<NXOpen::Features::SheetMetal::SheetmetalBendState> states;
        try
        {
            manager->GetInnerBendFaces(body, innerBendFaces, states);
        }
        catch (...)
        {
            return 0;
        }

        double thickness = 0.0;
        try
        {
            thickness = manager->GetBodyThickness(body);
        }
        catch (...)
        {
            thickness = 0.0;
        }

        std::map<tag_t, NXOpen::Features::Feature*> neutralFeatureByFace = BuildNeutralFactorFeatureByFace(body);
        std::map<tag_t, NXOpen::Features::Feature*> neutralFeaturesByTag;
        std::map<std::string, std::vector<NXOpen::Face*> > facesByRule;
        int prepared = 0;
        for (size_t i = 0; i < innerBendFaces.size(); ++i)
        {
            if (i < states.size() && states[i] != NXOpen::Features::SheetMetal::SheetmetalBendStateBent)
            {
                continue;
            }

            NXOpen::Face* face = innerBendFaces[i];
            if (face == NULL || !IsAlive(face->Tag()))
            {
                continue;
            }

            BendFaceRecord record;
            record.face = face;
            record.thickness = thickness;
            try
            {
                NXOpen::Features::SheetMetal::SheetmetalBendParameters parameters = manager->GetBendParameters(face);
                if (parameters.BendState != NXOpen::Features::SheetMetal::SheetmetalBendStateBent)
                {
                    continue;
                }

                record.innerRadius = parameters.InnerRadius;
                record.angleDeg = parameters.BendAngle;
                record.currentK = parameters.NeutralFactor;
            }
            catch (...)
            {
                continue;
            }

            const BendRule* rule = MatchRule(ruleConfig, record);
            if (rule == NULL || !CalculateTargetK(*rule, &record))
            {
                record.targetK = 0.5;
            }

            if (std::fabs(record.currentK - record.targetK) <= 1e-6)
            {
                continue;
            }

            NXOpen::Features::Feature* existingNeutralFeature = NULL;
            std::map<tag_t, NXOpen::Features::Feature*>::iterator existingIt = neutralFeatureByFace.find(face->Tag());
            if (existingIt != neutralFeatureByFace.end())
            {
                existingNeutralFeature = existingIt->second;
            }

            tag_t existingFeatureTag = existingNeutralFeature == NULL ? NULL_TAG : existingNeutralFeature->Tag();
            if (existingNeutralFeature != NULL)
            {
                neutralFeaturesByTag[existingFeatureTag] = existingNeutralFeature;
            }

            std::string key = std::to_string(static_cast<unsigned long long>(existingFeatureTag)) +
                "|" + FormatDouble(record.targetRadius > 0.0 ? record.targetRadius : record.innerRadius, 3) +
                "|" + FormatDouble(record.angleDeg, 3) +
                "|" + FormatDouble(record.targetK, 6);
            facesByRule[key].push_back(face);
            ++prepared;
        }

        int appliedFaces = 0;
        for (std::map<std::string, std::vector<NXOpen::Face*> >::iterator it = facesByRule.begin(); it != facesByRule.end(); ++it)
        {
            size_t lastPipe = it->first.find_last_of('|');
            double targetK = lastPipe == std::string::npos ? 0.5 : std::atof(it->first.substr(lastPipe + 1).c_str());
            tag_t existingFeatureTag = NULL_TAG;
            size_t firstPipe = it->first.find('|');
            if (firstPipe != std::string::npos)
            {
                existingFeatureTag = static_cast<tag_t>(std::strtoull(it->first.substr(0, firstPipe).c_str(), NULL, 10));
            }

            NXOpen::Features::Feature* existingNeutralFeature = NULL;
            std::map<tag_t, NXOpen::Features::Feature*>::iterator featureIt = neutralFeaturesByTag.find(existingFeatureTag);
            if (featureIt != neutralFeaturesByTag.end())
            {
                existingNeutralFeature = featureIt->second;
            }

            appliedFaces += CommitNeutralFactorFeature(part, existingNeutralFeature, it->second, targetK);
        }

        return appliedFaces == 0 ? prepared : appliedFaces;
    }

    NXOpen::Body* ResolveFeatureBody(NXOpen::Features::Feature* feature, NXOpen::Body* fallback)
    {
        if (feature == NULL)
        {
            return fallback;
        }

        try
        {
            std::vector<NXOpen::Body*> bodies = feature->GetBodies();
            if (!bodies.empty() && bodies[0] != NULL)
            {
                return bodies[0];
            }
        }
        catch (...)
        {
        }

        return fallback;
    }

    void RunCustomLibrary(char* libraryName)
    {
        char symbolName[] = "ufusr";
        UF_load_f_p_t functionPtr = NULL;
        int error = UF_load_library(libraryName, symbolName, &functionPtr);
        if (error != 0 || functionPtr == NULL)
        {
            throw std::runtime_error("加载外部 DLL 失败: " + std::string(libraryName));
        }

        functionPtr();
        UF_unload_library(libraryName);
    }

    bool IsEdgeOnFace(NXOpen::Edge* edge, NXOpen::Face* face)
    {
        if (edge == NULL || face == NULL)
        {
            return false;
        }

        std::vector<NXOpen::Edge*> faceEdges = face->GetEdges();
        for (size_t i = 0; i < faceEdges.size(); ++i)
        {
            if (faceEdges[i] != NULL && faceEdges[i]->Tag() == edge->Tag())
            {
                return true;
            }
        }

        return false;
    }

    bool IsStraightEdge(NXOpen::Edge* edge)
    {
        if (edge == NULL)
        {
            return false;
        }

        UF_EVAL_p_t evaluator1;
        bool isLine = false;
        int error = UF_EVAL_initialize(edge->Tag(), &evaluator1);
        if (error != 0)
        {
            return false;
        }

        error = UF_EVAL_is_line(evaluator1, &isLine);
        return error == 0 && isLine;
    }

    bool BodyHasStraightEdge(NXOpen::Body* body)
    {
        if (body == NULL)
        {
            return false;
        }

        std::vector<NXOpen::Edge*> bodyEdges = body->GetEdges();
        for (size_t i = 0; i < bodyEdges.size(); ++i)
        {
            if (IsStraightEdge(bodyEdges[i]))
            {
                return true;
            }
        }

        return false;
    }

    NXOpen::Features::Feature* CreateDefaultFlatPattern(NXOpen::Face* face)
    {
        if (face == NULL)
        {
            throw std::runtime_error("请选择有效的展开基面。");
        }

        NXOpen::Features::Feature* nullNXOpen_Features_Feature(NULL);
        NXOpen::Features::SheetMetal::FlatPatternBuilder* flatPatternBuilder1;
        flatPatternBuilder1 = workPart->Features()->SheetmetalManager()->CreateFlatPatternBuilder(nullNXOpen_Features_Feature);
        flatPatternBuilder1->SetApplicationContext(NXOpen::Features::SheetMetal::ApplicationContextNxSheetMetal);
        flatPatternBuilder1->SetOrientation(NXOpen::Features::SheetMetal::FlatSolidBuilder::OrientationTypeDefault);
        flatPatternBuilder1->OuterCornerTreatment()->SetTreatmentType(NXOpen::Features::SheetMetal::CornerTreatmentBuilder::CornerTreatmentTypeRadius);
        flatPatternBuilder1->OuterCornerTreatment()->Value()->SetFormula("1");
        flatPatternBuilder1->UpwardFace()->SetValue(face);

        NXOpen::Features::Feature* flatPatternFeature = flatPatternBuilder1->CommitFeature();
        flatPatternBuilder1->Destroy();
        theSession->CleanUpFacetedFacesAndEdges();
        return flatPatternFeature;
    }

