void SouDonZuanBanJin::baobian()
{
    RefreshNxContext();
    if (feature1 == NULL)
    {
        return;
    }
    std::vector<Face*>Faces1 = feature1->GetFaces();
    std::vector<Face*>Faces2;



    for (size_t i = 0; i < Faces1.size(); i++)
    {
        int type1;
        double point[3];
        double dir[3];
        double box[6];
        double radius;
        double rad_data;
        int norm_dir;
        UF_MODL_ask_face_data(Faces1[i]->Tag(), &type1, point, dir, box, &radius, &rad_data, &norm_dir);//查询面的数据

        if (fabs(radius - 0.2) < 0.01)
        {

            Faces2.push_back(Faces1[i]);
        }
    }
    for (size_t i = 0; i < Faces2.size(); i++)
    {

        for (size_t b = i + 1; b < Faces2.size(); b++)
        {

            MeasureDistance* measureDistance1;
            measureDistance1 = workPart->MeasureManager()->NewDistance(NULL, MeasureManager::MeasureTypeMinimum, Faces2[i], Faces2[b]);
            double distance1 = measureDistance1->Value();//获取测量的值

            if (distance1 == 0)
            {
                NXOpen::MeasureAngle* MeasAngle1;
                MeasAngle1 = workPart->MeasureManager()->NewAngle(NULL, Faces2[i], MeasureManager::EndpointTypeStartPoint, Faces2[b], MeasureManager::EndpointTypeStartPoint, true, false);
                double Angle1 = MeasAngle1->Value();

                NXOpen::Features::Feature* nullNXOpen_Features_Feature(NULL);
                NXOpen::Features::SheetMetal::ClosedCornerBuilder* closedCornerBuilder1;
                closedCornerBuilder1 = workPart->Features()->SheetmetalManager()->CreateClosedCornerFeatureBuilder(nullNXOpen_Features_Feature);
                closedCornerBuilder1->Gap()->SetFormula("0.2");
                closedCornerBuilder1->Overlap()->SetFormula("1");
                closedCornerBuilder1->SetCutMethod(NXOpen::Features::SheetMetal::ClosedCornerBuilder::CutMethodTypesByPath);
                closedCornerBuilder1->SetOverlapType(NXOpen::Features::SheetMetal::ClosedCornerBuilder::OverlapTypeOptionsSide2);

                std::vector<IParameterizedSurface*> objects1(1);
                objects1[0] = Faces2[i];
                MeasureFaces* measureFaces1;
                measureFaces1 = workPart->MeasureManager()->NewFaceProperties(NULL, NULL, 0.9999, objects1);
                double area1 = measureFaces1->Area();
                objects1[0] = Faces2[b];

                measureFaces1 = workPart->MeasureManager()->NewFaceProperties(NULL, NULL, 0.9999, objects1);
                double area2 = measureFaces1->Area();
                if (area1 >= area2)
                {
                    closedCornerBuilder1->AddFacePair(Faces2[i], Faces2[b]);
                }
                else
                {
                    closedCornerBuilder1->AddFacePair(Faces2[b], Faces2[i]);
                }

                NXOpen::Features::Feature* feature1a;
                feature1a = closedCornerBuilder1->CommitFeature();
                closedCornerBuilder1->Destroy();
                objects1a.push_back(feature1a);
            }
        }
    }

}

